Minimal fix (keep strict by default, add optional skew window):

```js
const DEFAULT_CLOCK_SKEW_MS = 0;

export async function authMiddleware(req, res, next) {
  const token = getBearerToken(req);
  if (!token) return res.status(401).json({ error: 'missing_token' });

  const payload = verifyJwt(token);
  const nowMs = Date.now();
  const expMs = payload.exp * 1000;
  const skewMs = Number(process.env.AUTH_CLOCK_SKEW_MS ?? DEFAULT_CLOCK_SKEW_MS);

  if (expMs + skewMs < nowMs) {
    return res.status(401).json({ error: 'expired_token' });
  }

  req.userId = payload.sub;
  return next();
}
```

Regression test (Jest; verifies boundary acceptance within 30s, and preserves old behavior when unset):

```js
import { authMiddleware } from './authMiddleware';

test('allows exp==now within configured clock skew (prevents refresh loop)', async () => {
  process.env.AUTH_CLOCK_SKEW_MS = '30000';
  jest.spyOn(Date, 'now').mockReturnValue(1_000_000);
  global.getBearerToken = jest.fn(() => 't');
  global.verifyJwt = jest.fn(() => ({ exp: 1000, sub: 'u1' })); // expMs == nowMs

  const req = {};
  const res = { status: jest.fn(() => res), json: jest.fn() };
  const next = jest.fn();

  await authMiddleware(req, res, next);

  expect(next).toHaveBeenCalled();
  expect(req.userId).toBe('u1');
  expect(res.status).not.toHaveBeenCalled();
});

test('backward compatible: without skew, exp==now is still accepted', async () => {
  delete process.env.AUTH_CLOCK_SKEW_MS;
  jest.spyOn(Date, 'now').mockReturnValue(1_000_000);
  global.getBearerToken = jest.fn(() => 't');
  global.verifyJwt = jest.fn(() => ({ exp: 1000, sub: 'u1' }));

  const req = {};
  const res = { status: jest.fn(() => res), json: jest.fn() };
  const next = jest.fn();

  await authMiddleware(req, res, next);

  expect(next).toHaveBeenCalled();
});
```

