const { promisify } = require('util');

const findUser = promisify(db.findUser.bind(db));
const auditLog = promisify(audit.log.bind(audit));
const cacheSet = promisify(cache.set.bind(cache));

async function loadUser(id, next) {
  if (!id) return next(new Error('missing_id'));

  try {
    const user = await findUser(id);
    if (!user) return next(new Error('not_found'));

    await auditLog(user.id);
    await cacheSet(user.id, user);

    return next(null, user);
  } catch (err) {
    return next(err);
  }
}
